public class NoviApi {
    public static void main(String[] args) {
    	String url = "http://127.0.0.1:8888/api/v1/receipt/7397fdc223df39207bcd0e473eea0364";
    	String token = "eyJ0eXAiOiJKV1QiLCJhbGciOiJIUzI1NiJ9.eyJpc3MiOiJaQk4xOTAxMDA3MDk0Iiwic3ViIjoiTm92aUFwaSIsImV4cCI6IjIwMjMtMDYtMTNUMDg6MzE6NTJaIiwianRpIjoiZDY4NTljYmQzZDE3MGQzMjQ0YmU3MTlhNjRlZGMwY2UifQ.6r31hBNthrC9n9fhxAQfAAoOn34fQByeDHsQKB60p_c";

    	getRequest(url, token);
    }

	public static void getRequest(String url, String token)
	{
		HttpClient client = HttpClient.newHttpClient();

		HttpRequest request = HttpRequest.newBuilder()
				.uri(URI.create(url))
				.GET()
				.header("Authorization", "Bearer " + token)
				.build();

		client.sendAsync(request, BodyHandlers.ofString())
		      .thenApply(HttpResponse::body)
		      .thenAccept(System.out::println)
		      .join();
	}
}

